import React, { useState, useRef, useEffect } from 'react';
import { collegeData } from '../data/collegeData'; 
import { Bot, Send, X, Loader2 } from 'lucide-react';

// 🚨 SPLIT KEY TRICK (Safe for GitHub)
const part1 = "AIzaSyAzJtMQSarM6NT42";
const part2 = "Zz8dUK5VM3PqW7VoWM";
const API_KEY = part1 + part2; 

function ChatBot({ isOpen, onClose, onOpen }) {
  const [messages, setMessages] = useState([
    { text: "Hi! I'm CampusBot. I'm online and ready to help. Ask me about NIMIT or code!", isBot: true }
  ]);
  const [input, setInput] = useState("");
  const [isThinking, setIsThinking] = useState(false);
  const messagesEndRef = useRef(null);

  // Auto-scroll logic
  useEffect(() => {
    if (isOpen) {
       messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages, isThinking, isOpen]);

  const handleSend = async () => {
    if (!input.trim()) return;

    // 1. Add User Message
    const userMsg = { text: input, isBot: false };
    setMessages((prev) => [...prev, userMsg]);
    setInput("");
    setIsThinking(true);

    try {
      // 2. Prepare the AI "Brain"
      const systemContext = `
        You are "CampusBot", the AI assistant for ${collegeData?.collegeInfo?.name || "NIMIT"}.
        
        DATA:
        - Departments: ${collegeData?.collegeInfo?.departments?.join(", ") || "CS, Commerce, Management"}
        - Events: ${collegeData?.collegeInfo?.campusLife?.majorEvents?.join(", ") || "Arts, Sports"}
        
        INSTRUCTIONS:
        1. If asked about the college, use the data above.
        2. If data is missing or the question is General (Math, Coding, Science), answer as a helpful expert AI.
        3. Be concise.
      `;

      // 3. 🚨 DIRECT INTERNET CALL
      // We switched from 'gemini-pro' (which caused your 404) to 'gemini-1.5-flash'.
      const response = await fetch(
        `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${API_KEY}`,
        {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify({
            contents: [{
              parts: [{ text: systemContext + "\n\nUser Question: " + userMsg.text }]
            }]
          }),
        }
      );

      const data = await response.json();

      // 4. Handle Errors from Google
      if (data.error) {
        throw new Error(data.error.message);
      }

      // 5. Success! Get the text.
      const aiResponse = data.candidates?.[0]?.content?.parts?.[0]?.text || "I'm not sure, try asking again.";
      
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: aiResponse, isBot: true }]);

    } catch (error) {
      console.error("Chat Error:", error);
      setIsThinking(false);
      setMessages((prev) => [...prev, { text: "⚠️ Server Error. Please try again.", isBot: true }]);
    }
  };

  // --- UI RENDER ---
  return (
    <div className="fixed bottom-6 right-6 z-50 font-sans">
      
      {/* Floating Button */}
      {!isOpen && (
        <button 
          onClick={onOpen}
          className="w-14 h-14 bg-indigo-600 rounded-full shadow-lg flex items-center justify-center border border-white/20 animate-bounce text-white hover:scale-110 transition-transform"
        >
          <Bot size={24} />
        </button>
      )}

      {/* Chat Window */}
      {isOpen && (
        <div className="w-[350px] md:w-[380px] h-[500px] bg-[#0a0a0a] border border-white/20 rounded-2xl shadow-2xl flex flex-col overflow-hidden animate-in fade-in slide-in-from-bottom-4">
          
          {/* Header */}
          <div className="bg-indigo-900/50 border-b border-white/10 p-4 flex items-center justify-between">
            <div className="flex items-center gap-2">
              <Bot className="text-indigo-400" size={20} />
              <span className="text-white font-bold">CampusBot AI</span>
            </div>
            <button onClick={onClose} className="text-gray-400 hover:text-white"><X size={20} /></button>
          </div>

          {/* Messages */}
          <div className="flex-1 overflow-y-auto p-4 space-y-4">
            {messages.map((msg, index) => (
              <div key={index} className={`flex ${msg.isBot ? 'justify-start' : 'justify-end'}`}>
                <div className={`max-w-[85%] p-3 text-sm rounded-xl shadow-md ${
                  !msg.isBot 
                    ? 'bg-indigo-600 text-white rounded-tr-none' 
                    : 'bg-[#1a1a1a] text-gray-200 border border-white/10 rounded-tl-none'
                }`}>
                  {/* Markdown-ish rendering for Code Blocks */}
                  {msg.text.split('```').map((part, i) => 
                    i % 2 === 1 ? (
                      <code key={i} className="block bg-black/50 p-2 rounded text-xs my-1 font-mono text-green-400 overflow-x-auto border border-white/10">{part}</code>
                    ) : (
                      <span key={i} className="whitespace-pre-wrap">{part}</span>
                    )
                  )}
                </div>
              </div>
            ))}
            {isThinking && (
              <div className="flex items-center gap-2 text-indigo-400 text-xs p-2">
                <Loader2 className="w-3 h-3 animate-spin" /> Thinking...
              </div>
            )}
            <div ref={messagesEndRef} />
          </div>

          {/* Input */}
          <div className="p-3 bg-black border-t border-white/10 flex gap-2">
            <input 
              type="text" 
              value={input} 
              onChange={(e) => setInput(e.target.value)} 
              onKeyPress={(e) => e.key === 'Enter' && handleSend()}
              placeholder="Ask anything..." 
              className="flex-1 bg-[#1a1a1a] border border-white/10 rounded-lg px-3 py-2 text-sm text-white focus:outline-none focus:border-indigo-500 placeholder-gray-500"
            />
            <button 
              onClick={handleSend} 
              disabled={isThinking || !input.trim()} 
              className="bg-indigo-600 p-2 rounded-lg text-white disabled:opacity-50 hover:bg-indigo-500 transition-colors"
            >
              <Send size={18} />
            </button>
          </div>

        </div>
      )}
    </div>
  );
}

export default ChatBot;
